interface.definition:
a!localVariables(
  local!socialScore: 42,
  local!selectedService,
  local!initialRequest: #"urn:appian:record-type:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a"(
    #"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/bd55e7e8-03c6-4f77-988b-8b8f254043d2": false,
    #"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3ae6d220-0450-4065-b61f-4b136d605959": loggedInUser(),
    #"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/f51c6f76-9293-444e-91b7-3287f0bd53b9": now(),
    #"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/df425fdb-0f35-4150-a497-dbf371bc0c0f": #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068411"
  ),
  local!request: local!initialRequest,
  local!selectedMonth,
  local!selectedDay,
  #"SYSTEM_SYSRULES_headerContentLayout"(
    header: #"SYSTEM_SYSRULES_cardLayout"(
      contents: {
        #"SYSTEM_SYSRULES_sideBySideLayout"(
          items: {
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  "   ",
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "reply",
                    link: #"SYSTEM_SYSRULES_dynamicLink"(
                      value: null,
                      saveInto: ri!function
                    ),
                    linkStyle: "STANDALONE",
                    color: "#000000",
                    size: "LARGE_PLUS"
                  )
                }
              )
            ),
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  #"SYSTEM_SYSRULES_richTextItem_v1"(
                    text: "SERVICE",
                    size: "LARGE"
                  )
                }
              ),
              width: "MINIMIZE"
            ),
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "shopping-cart",
                    color: "",
                    size: "EXTRA_LARGE"
                  )
                },
                align: "RIGHT"
              ),
              width: "MINIMIZE"
            )
          },
          alignVertical: "MIDDLE"
        )
      },
      style: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[2],
      showBorder: false
    ),
    contents: a!localVariables(
      local!services: #"SYSTEM_SYSRULES_queryRecordType_v1"(
        recordType: #"urn:appian:record-type:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38",
        pagingInfo: #"SYSTEM_SYSRULES_pagingInfo"(
          1,
          100
        )
      ),
      {
        #"SYSTEM_SYSRULES_cardLayout"(
          contents: {
            #"SYSTEM_SYSRULES_cardGroupLayout"(
              labelPosition: "COLLAPSED",
              cards: #"SYSTEM_SYSRULES_forEach"(
                items: local!services.data,
                expression: #"SYSTEM_SYSRULES_cardLayout"(
                  contents: {
                    #"SYSTEM_SYSRULES_columnsLayout"(
                      columns: {
                        #"SYSTEM_SYSRULES_columnLayout"(
                          contents: {
                            #"SYSTEM_SYSRULES_richTextDisplayField"(
                              labelPosition: "COLLAPSED",
                              value: #"SYSTEM_SYSRULES_richTextIcon"(
                                icon: fv!item[#"urn:appian:record-field:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38/e6e355ad-959a-48b6-b75b-3ebd0e14ab88"],
                                size: "EXTRA_LARGE"
                              )
                            )
                          },
                          width: "EXTRA_NARROW"
                        ),
                        #"SYSTEM_SYSRULES_columnLayout"(
                          contents: {
                            #"SYSTEM_SYSRULES_sideBySideLayout"(
                              items: {
                                #"SYSTEM_SYSRULES_sideBySideItem"(
                                  item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                                    labelPosition: "COLLAPSED",
                                    value: {
                                      #"SYSTEM_SYSRULES_richTextItem_v1"(
                                        text: fv!item[#"urn:appian:record-field:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38/beca9641-3846-41ea-a60f-6431df182394"],
                                        size: "MEDIUM_PLUS"
                                      )
                                    }
                                  )
                                ),
                                #"SYSTEM_SYSRULES_sideBySideItem"(
                                  item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                                    labelPosition: "COLLAPSED",
                                    value: {
                                      #"SYSTEM_SYSRULES_richTextIcon"(
                                        icon: if(
                                          fv!item[#"urn:appian:record-field:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38/d6f37442-2972-49b3-b01c-d268e714af0c"] < local!socialScore,
                                          "check-circle",
                                          "ban"
                                        ),
                                        color: if(
                                          fv!item[#"urn:appian:record-field:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38/d6f37442-2972-49b3-b01c-d268e714af0c"] < local!socialScore,
                                          "POSITIVE",
                                          "NEGATIVE"
                                        ),
                                        size: "MEDIUM_PLUS"
                                      )
                                    }
                                  ),
                                  width: "MINIMIZE"
                                )
                              }
                            ),
                            #"SYSTEM_SYSRULES_richTextDisplayField"(
                              labelPosition: "COLLAPSED",
                              value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                                text: "Sprich mit deinem Sozialarbeiter wie du dich einbringen kannst um deinen Score zu erhöhen.",
                                color: "NEGATIVE",
                                size: "MEDIUM",
                                style: "STRONG"
                              ),
                              showWhen: fv!item[#"urn:appian:record-field:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38/d6f37442-2972-49b3-b01c-d268e714af0c"] > local!socialScore
                            ),
                            #"SYSTEM_SYSRULES_richTextDisplayField"(
                              labelPosition: "COLLAPSED",
                              value: {
                                fv!item[#"urn:appian:record-field:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38/c3554570-228f-4ac1-9ef6-bf311dbacebf"]
                              }
                            )
                          }
                        )
                      }
                    )
                  },
                  link: if(
                    fv!item[#"urn:appian:record-field:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38/3c5611e0-e036-4ccf-bfc1-f4c39f1d9519"] = 1,
                    #"SYSTEM_SYSRULES_dynamicLink"(
                      value: fv!item[#"urn:appian:record-field:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38/3c5611e0-e036-4ccf-bfc1-f4c39f1d9519"],
                      saveInto: local!selectedService
                    ),
                    null
                  ),
                  style: if(
                    fv!item[#"urn:appian:record-field:v1:309979c2-c7d9-40f7-b1a6-8b97ce1f4b38/d6f37442-2972-49b3-b01c-d268e714af0c"] < local!socialScore,
                    "STANDARD",
                    "#333333"
                  ),
                  shape: "ROUNDED",
                  showBorder: false
                )
              )
            )
          },
          showWhen: a!isNullOrEmpty(local!selectedService),
          style: "TRANSPARENT",
          showBorder: false
        ),

        #"SYSTEM_SYSRULES_cardLayout"(
          contents: {
            #"SYSTEM_SYSRULES_sectionLayout_v1"(
              label: "Besuch Beantragen",
              labelIcon: "calendar",
              labelSize: "LARGE",
              contents: {
                #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: {
                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                      text: "Wähle maximal 3 Besucher und gib den Termin und einen Grund an.",
                      size: "MEDIUM"
                    )
                  }
                ),
                #"SYSTEM_SYSRULES_cardChoiceField"(
                  labelPosition: "COLLAPSED",
                  data: {
                    {guest: "Oma Gertrud", label: "Oma Gertrud", icon: "user-alt"},
                    {guest: "Ehefrau Sabine", label: "Ehefrau Sabine", icon: "user"},
                    {guest: "Bruder Mickey", label: "Bruder Mickey", icon: "user-secret"},
                    {guest: "Tochter Hanna", label: "Tochter Hanna", icon: "child"},
                    {guest: "Sohn Detlef", label: "Sohn Detlef", icon: "baby"},
                  },
                  cardTemplate: #"SYSTEM_SYSRULES_cardTemplateBarTextStacked"(
                    id: fv!data.guest,
                    primaryText: fv!data.label,
                    icon: fv!data.icon
                  ),
                  required: true,
                  maxSelections: 3,
                  value: if(
                    a!isNullOrEmpty(local!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3bc83589-99d7-4e39-9aab-a543720daca7"]),
                    null,
                    split(local!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3bc83589-99d7-4e39-9aab-a543720daca7"], ";")
                  ),
                  saveInto: a!save(
                    target: local!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/3bc83589-99d7-4e39-9aab-a543720daca7"],
                    value: joinarray(save!value, ";")
                  )
                ),
                #"SYSTEM_SYSRULES_ButtonArrayLayout"(
                  buttons: #"SYSTEM_SYSRULES_forEach"(
                    items: enumerate(12),
                    expression: #"SYSTEM_SYSRULES_buttonWidget_v1"(
                      label: text(date(year(today()), fv!index, 1), "mmmm"),
                      value: fv!index,
                      saveInto: local!selectedMonth,
                      style: if(
                        or(
                          a!isNullOrEmpty(local!selectedMonth),
                          local!selectedMonth = fv!index
                        ),
                        "SOLID",
                        "GHOST"
                      )
                    )
                  )
                ),
                #"SYSTEM_SYSRULES_ButtonArrayLayout"(
                  showWhen: a!isNotNullOrEmpty(local!selectedMonth),
                  buttons: #"SYSTEM_SYSRULES_forEach"(
                    items: enumerate(day(eomonth(date(year(today()), local!selectedMonth, 1), 0))),
                    expression: #"SYSTEM_SYSRULES_buttonWidget_v1"(
                      label: text(date(year(today()), local!selectedMonth, fv!index), "d"),
                      value: fv!index,
                      saveInto: local!selectedDay,
                      style: if(
                        or(
                          a!isNullOrEmpty(local!selectedDay),
                          local!selectedDay = fv!index
                        ),
                        "SOLID",
                        "GHOST"
                      )
                    )
                  )
                ),
                #"SYSTEM_SYSRULES_paragraphField"(
                  label: "Grund",
                  value: local!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/71d51822-db2b-4543-b00e-364428dbdfbc"],
                  saveInto: local!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/71d51822-db2b-4543-b00e-364428dbdfbc"],
                  required: true
                )
              }
            ),
            #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1605697"(
              text: {
                "Dein Antrag wird von deinem Betreuer geprüft.",
                "Rückfragen beantwortest du über deine Aufgaben.",
                "Der Besuch wird mit deinem Gast vereinbart."
              },
              labelSize: "MEDIUM_PLUS",
              textSize: "MEDIUM"
            ),
            #"SYSTEM_SYSRULES_ButtonLayout"(
              primaryButtons: {
                #"SYSTEM_SYSRULES_buttonWidget_v1"(
                  label: "Besuch Beantragen",
                  icon: "check",
                  size: "LARGE",
                  style: "SOLID",
                  validate: true,
                  saveInto: {
                    a!save(
                      target: local!request[#"urn:appian:record-field:v1:2e4db39a-2f38-4769-b11e-8ad8441f993a/1248a4bf-108e-4870-8db8-2816b7cd4bea"],
                      value: date(year(today()), local!selectedMonth, local!selectedDay)
                    ),
                    #"SYSTEM_SYSRULES_startProcess3"(
                      processModel: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1067817",
                      processParameters: {
                        request: local!request
                      }
                    ),
                    a!save(
                      target: {local!selectedDay, local!selectedMonth, local!selectedService},
                      value: null
                    ),
                    a!save(
                      target: local!request,
                      value: local!initialRequest
                    )
                  }
                )
              },
              secondaryButtons: {
                #"SYSTEM_SYSRULES_buttonWidget_v1"(
                  label: "Abbrechen",
                  icon: "close",
                  value: null,
                  saveInto: {
                    local!selectedService,
                    local!selectedDay,
                    local!selectedMonth,
                    a!save(
                      target: local!request,
                      value: local!initialRequest
                    )
                  },
                  size: "LARGE",
                  color: "SECONDARY"
                )
              }
            )
          },
          showWhen: tointeger(local!selectedService) = 1,
          style: "#333333",
          shape: "ROUNDED",
          showBorder: false
        )
      }
    ),
    backgroundColor: "#111111"
  )
)
